import { FoldersApi, type ResponsesFolderData } from '@/api';
import { useAuth } from '@/contexts/AuthContext';
import { cn } from '@/utils/cn';
import { createEffect, createMemo, createSignal, type ComponentProps } from 'solid-js';

interface FolderComponentProps extends ComponentProps<'div'> {
	folder: ResponsesFolderData;
	selectedFolder: () => string;
	setSelectedFolder: (id: string) => void;
	deleteFolder: (id: string) => void;
	indent?: number;
}

export default function FolderComponent(props: FolderComponentProps) {
	const { folder, selectedFolder, setSelectedFolder, deleteFolder, indent } =
		props;
	const foldersApi = new FoldersApi();

	const [isFolderOpen, setIsFolderOpen] = createSignal(false);
	createEffect(() => {
		console.log(folder);
	});

	const [children, setChildren] = createSignal<ResponsesFolderData[]>(folder.children || []);

	const auth = useAuth();

	const openFolder = async () => {
		if (folder.children && folder.children.length > 0) {
			setIsFolderOpen(!isFolderOpen());
		} else {
			// try to get the folder content from the server
			const response = await foldersApi.getFolders({
				folderId: folder.id || '',
				authorization: `Bearer ${auth.token()}`,
			})
			if (response.success && response.data?.children) {
				console.log(response.data.children);
				setChildren(response.data.children || []);
				setIsFolderOpen(true);
			} else {
				console.error('Failed to get folder content:', response.message, response.data, response.success);
			}
		}
	};

	const renderChildren = () => createMemo(() => {
		if (children && children().length > 0) {
			return (
				<div class="space-y-4">
					{folder.children.map((child) => (
						<FolderComponent
							folder={child}
							selectedFolder={selectedFolder}
							setSelectedFolder={setSelectedFolder}
							deleteFolder={deleteFolder}
							indent={indent ? indent + 2 : 2}
						/>
					))}
				</div>
			);
		}
	}, [children]);

	return (
		<>
			<div
				class={cn(
					`flex items-center py-1 px-2 cursor-pointer bg-primary text-primary-foreground hover:bg-primary/80 rounded-lg
		shadow-md hover:shadow-lg transition-all duration-200 shadow-slate-900/80 ease-in-out`,
					folder.id === selectedFolder() && 'bg-primary/80',
					indent && `ml-${indent}`,
				)}
				onClick={() => {
					setSelectedFolder(folder.id || '');
					openFolder();
				}}
			>
				<span class="mr-2 text-sm">📁</span>
				<span class="mr-2 text-sm">{folder.name}</span>
				<button
					onClick={(e) => {
						e.stopPropagation();
						deleteFolder(folder.id || '');
					}}
					class="ml-2 text-red-500 hover:text-red-700 text-xs px-1"
					title="Delete folder"
				>
					🗑
				</button>
			</div>
			{isFolderOpen() && renderChildren()}
		</>
	);
}
